const query = $('Webhook — GET /vmm-sp-employee').first().json.query || {};
const code = (query.code || '').toString().trim();

const all = $input.all();

const mapEmp = (item) => {
  const e = item.json;
  return {
    name:        e['Employee Name'] || '',
    code:        e['Employee Code'] || '',
    email:       e['E-mail'] || '',
    mobile:      e['Mobile No.'] || '',
    alternateNo: e['Alternative No.'] || '',
    designation: e['Designation'] || '',
    status:      e['Status'] || '',
    storeCode:   e['Store Code'] || '',
    storeName:   e['Store Name'] || '',
    city:        e['City'] || '',
    region:      e['Region'] || '',
    state:       e['State'] || '',
    zone:        e['Zone'] || '',
    managerName: e['Manager Name'] || '',
    asmName:     e['ASM name'] || '',
    fmName:      e['FM Name'] || '',
    fmEmail:     e['FM Email'] || '',
  };
};

// No code param → return full list for autocomplete
if (!code) {
  const employees = all.map(mapEmp).filter(e => e.code !== '');
  return [{ json: { found: true, employees, count: employees.length } }];
}

// Exact code lookup
const match = all.find(item =>
  (item.json['Employee Code'] || '').toString().trim() === code
);

if (!match) {
  return [{ json: { found: false, code, message: 'Employee not found' } }];
}

return [{ json: { found: true, employee: mapEmp(match) } }];
